.gv-folder-import-radio-option {
  display: flex;
  align-items: center;
  padding: 12px 14px;
  border: 1.5px solid oklch(0.92 0.004 250 / 0.7);
  border-radius: 10px;
  cursor: pointer;
  transition: all 0.15s cubic-bezier(0.4, 0, 0.2, 1);
}

.gv-folder-import-radio-option:hover {
  background: oklch(0.55 0.17 155 / 0.06);
  border-color: oklch(0.55 0.17 155 / 0.4);
}

@media (prefers-color-scheme: dark) {
  .gv-folder-import-radio-option {
    border-color: oklch(0.3 0.008 285 / 0.7);
  }
  .gv-folder-import-radio-option:hover {
    background: oklch(0.7 0.16 155 / 0.08);
    border-color: oklch(0.7 0.16 155 / 0.4);
  }
}

html.dark .gv-folder-import-radio-option,
[data-theme='dark'] .gv-folder-import-radio-option,
[data-color-scheme='dark'] .gv-folder-import-radio-option {
  border-color: oklch(0.3 0.008 285 / 0.7);
}

html.dark .gv-folder-import-radio-option:hover,
[data-theme='dark'] .gv-folder-import-radio-option:hover,
[data-color-scheme='dark'] .gv-folder-import-radio-option:hover {
  background: oklch(0.7 0.16 155 / 0.08);
  border-color: oklch(0.7 0.16 155 / 0.4);
}

.gv-folder-import-radio-option input[type='radio'] {
  margin-right: 12px;
  cursor: pointer;
  accent-color: oklch(0.55 0.17 155);
}

.gv-folder-import-radio-option span {
  font-size: 13px;
  font-weight: 500;
  color: oklch(0.14 0.004 285);
}

@media (prefers-color-scheme: dark) {
  .gv-folder-import-radio-option span {
    color: oklch(0.92 0.004 250);
  }
}

html.dark .gv-folder-import-radio-option span,
[data-theme='dark'] .gv-folder-import-radio-option span,
[data-color-scheme='dark'] .gv-folder-import-radio-option span {
  color: oklch(0.92 0.004 250);
}

/* File input */
.gv-folder-import-file-input {
  margin-bottom: 20px;
}

.gv-folder-import-file-button {
  background: oklch(0.55 0.17 155);
  color: oklch(0.99 0.01 155);
  border: none;
  padding: 10px 20px;
  border-radius: 9px;
  cursor: pointer;
  font-size: 13px;
  font-weight: 700;
  transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
  width: 100%;
  box-shadow: 0 2px 8px oklch(0.55 0.17 155 / 0.3);
}

.gv-folder-import-file-button:hover {
  background: oklch(0.6 0.2 158);
  box-shadow: 0 4px 14px oklch(0.55 0.17 155 / 0.4);
  transform: translateY(-1px);
}

@media (prefers-color-scheme: dark) {
  .gv-folder-import-file-button {
    background: oklch(0.7 0.16 155);
    color: oklch(0.15 0.025 160);
    box-shadow: 0 2px 8px oklch(0.7 0.16 155 / 0.3);
  }
  .gv-folder-import-file-button:hover {
    background: oklch(0.7 0.2 155);
    box-shadow: 0 4px 14px oklch(0.7 0.16 155 / 0.4);
  }
}

.gv-folder-import-file-name {
  margin-top: 12px;
  font-size: 12px;
  font-weight: 500;
  color: oklch(0.14 0.004 285 / 0.5);
  padding: 9px 12px;
  background: oklch(0.14 0.004 285 / 0.04);
  border-radius: 10px;
  text-align: center;
  min-height: 32px;
  display: flex;
  align-items: center;
  justify-content: center;
}

@media (prefers-color-scheme: dark) {
  .gv-folder-import-file-name {
    background: oklch(0.92 0.004 250 / 0.06);
    color: oklch(0.92 0.004 250 / 0.5);
  }
}

