/* Conversation Item in Folder */
.gv-folder-conversation {
  display: flex;
  align-items: center;
  gap: 4px;
  padding: 8px 6px;
  border-radius: 8px;
  cursor: pointer;
  transition:
    background-color 0.15s ease,
    opacity 0.2s;
  position: relative;
}

.gv-folder-conversation:hover {
