  font-size: 0;
  /* Hide text like 'push_pin' */
  line-height: 20px;
  display: inline-block;
  width: 20px;
  /* bigger box to avoid clipping */
  height: 20px;
  overflow: hidden;
  vertical-align: middle;
}

.gv-aistudio .google-symbols::before {
  display: block;
  width: 20px;
  height: 20px;
  line-height: 20px;
  text-align: center;
  font-size: 18px;
}

